#!/usr/bin/env node
/**
 * gen-wordlists.mjs — convert adjectives.txt and nouns.txt into a TS module.
 *
 * This script regenerates `src/wordlists.generated.ts` whenever the canonical
 * wordlist files at the repo root change. The generated file is COMMITTED to
 * the repo so consumers can `pnpm add github:SamHarrison/arxivhaiku` and get
 * a fully-built package without running this script themselves.
 *
 * A CI check (.github/workflows/ci.yml) re-runs this script on every PR and
 * fails if the generated file would diff from what's committed — that's the
 * mechanism that prevents the Python wordlists and the TS module from
 * silently drifting out of sync.
 *
 * Usage:
 *   node scripts/gen-wordlists.mjs
 *   pnpm run gen
 */
import { createHash } from "node:crypto";
import { readFileSync, writeFileSync } from "node:fs";
import { dirname, join } from "node:path";
import { fileURLToPath } from "node:url";

const __dirname = dirname(fileURLToPath(import.meta.url));
const ROOT = join(__dirname, "..");

const ADJ_PATH = join(ROOT, "adjectives.txt");
const NOUN_PATH = join(ROOT, "nouns.txt");
const OUT_PATH = join(ROOT, "src", "wordlists.generated.ts");

const ADJ_EXPECTED = 4096; // 2^12
const NOUN_EXPECTED = 8192; // 2^13

function loadWordlist(path, expectedCount, label) {
  const raw = readFileSync(path, "utf8");
  const words = raw.split("\n").map((s) => s.trim()).filter(Boolean);
  if (words.length !== expectedCount) {
    throw new Error(
      `${label}: expected ${expectedCount} entries, got ${words.length} in ${path}`,
    );
  }
  // Defensive: enforce shape constraints
  for (const w of words) {
    if (!/^[a-z]{4,7}$/.test(w)) {
      throw new Error(`${label}: invalid entry "${w}" in ${path}`);
    }
  }
  const sha256 = createHash("sha256").update(raw).digest("hex");
  return { words, sha256 };
}

function formatArrayLiteral(words, perLine = 6) {
  // Pretty-print as multi-column literal for readable diffs.
  const lines = [];
  for (let i = 0; i < words.length; i += perLine) {
    const chunk = words
      .slice(i, i + perLine)
      .map((w) => JSON.stringify(w))
      .join(", ");
    lines.push(`  ${chunk},`);
  }
  return lines.join("\n");
}

function main() {
  const adj = loadWordlist(ADJ_PATH, ADJ_EXPECTED, "adjectives");
  const noun = loadWordlist(NOUN_PATH, NOUN_EXPECTED, "nouns");

  // Disjointness assertion — mirrors the Python quality gate.
  const adjSet = new Set(adj.words);
  for (const w of noun.words) {
    if (adjSet.has(w)) {
      throw new Error(`pools are not disjoint: ${w} appears in both`);
    }
  }

  const header = `// AUTO-GENERATED by scripts/gen-wordlists.mjs — do not edit by hand.
//
// Sources (SHA-256 pinned):
//   adjectives.txt  ${adj.sha256}
//   nouns.txt       ${noun.sha256}
//
// Regenerate with:  pnpm run gen
//
// The CI check fails if this file is out of sync with the .txt files.

export const ADJECTIVES: readonly string[] = Object.freeze([
${formatArrayLiteral(adj.words)}
]);

export const NOUNS: readonly string[] = Object.freeze([
${formatArrayLiteral(noun.words)}
]);

export const ADJECTIVES_SHA256 = ${JSON.stringify(adj.sha256)} as const;
export const NOUNS_SHA256 = ${JSON.stringify(noun.sha256)} as const;
`;

  writeFileSync(OUT_PATH, header, "utf8");
  console.log(`wrote ${OUT_PATH}`);
  console.log(`  adjectives: ${adj.words.length}  sha256=${adj.sha256.slice(0, 16)}…`);
  console.log(`  nouns:      ${noun.words.length}  sha256=${noun.sha256.slice(0, 16)}…`);
}

main();
